#include<bits/stdc++.h>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
typedef long long ll;const int N=2e5+10;
int n,dp[N],q[N],h,t=-1;ll s[N],g[N];
int main()
{
	n=read();rep(1,n,i)s[i]=s[i-1]+read();q[++t]=0;
	rep(1,n,i)
	{
//		printf("%d :: ",i);rep(h,t,i)printf("%d ",q[i]);puts("");
		while(h+1<=t&&s[i]>=s[q[h+1]]+g[q[h+1]])++h;
		dp[i]=dp[q[h]]+1;g[i]=s[i]-s[q[h]];
		while(h<=t&&s[q[t]]+g[q[t]]>s[i]+g[i])--t;q[++t]=i;
	}
	printf("%d\n",n-dp[n]);return 0;
}
